begin;
create extension if not exists pgcrypto;
create table if not exists public.revenue_os_command_families(id uuid primary key default gen_random_uuid(),code text unique not null,name text not null,description text not null,target_count integer not null check(target_count>0),sort_order integer not null default 0,owner_role text not null,active boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_definitions(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,command_code text unique not null,name text not null,family_code text not null references public.revenue_os_command_families(code),purpose text not null,owner_role text not null,status text not null check(status in('draft','proposed','under-review','needs-evidence','needs-approval','approved','rejected','scheduled','running','paused','blocked','failed','retrying','completed','superseded','retired','rolled-back','audited')),active_version text not null,business_units jsonb not null default '[]',segments jsonb not null default '[]',territories jsonb not null default '[]',commercial_stages jsonb not null default '[]',trigger_types jsonb not null default '[]',eligibility_rules jsonb not null default '[]',required_context jsonb not null default '[]',optional_context jsonb not null default '[]',tool_permissions jsonb not null default '[]',input_schema jsonb not null default '[]',output_schema jsonb not null default '[]',validator_chain jsonb not null default '[]',approval_class text not null check(approval_class in('none','recommendation','internal-generation','supervisor','department','director','executive','prohibited')),downstream_compiler text,cooldown_policy jsonb not null,retry_policy jsonb not null,failure_policy jsonb not null,fallback_command_codes jsonb not null default '[]',performance_metrics jsonb not null default '[]',prohibited_cases jsonb not null default '[]',expected_outcomes jsonb not null default '[]',tags jsonb not null default '[]',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid,updated_by uuid);
create table if not exists public.revenue_os_command_versions(id uuid primary key default gen_random_uuid(),command_id uuid not null references public.revenue_os_command_definitions(id) on delete restrict,command_code text not null,version text not null,status text not null,snapshot jsonb not null,schema_hash text not null,effective_at timestamptz not null,approved_at timestamptz,approved_by uuid,change_summary text not null,created_at timestamptz not null default now(),retired_at timestamptz,unique(command_code,version));
create table if not exists public.revenue_os_command_eligibility_rules(id uuid primary key default gen_random_uuid(),command_id uuid not null references public.revenue_os_command_definitions(id) on delete cascade,rule_code text not null,field_path text not null,operator text not null,expected_value jsonb,weight integer not null default 0,hard_block boolean not null default false,reason text not null,sort_order integer not null default 0,active boolean not null default true,created_at timestamptz not null default now(),unique(command_id,rule_code));
create table if not exists public.revenue_os_command_context_contracts(id uuid primary key default gen_random_uuid(),command_id uuid not null references public.revenue_os_command_definitions(id) on delete cascade,context_key text not null,label text not null,required boolean not null,freshness_minutes integer,allowed_states jsonb not null,source_domains jsonb not null,confidentiality text not null,created_at timestamptz not null default now(),unique(command_id,context_key));
create table if not exists public.revenue_os_command_tool_permissions(id uuid primary key default gen_random_uuid(),command_id uuid not null references public.revenue_os_command_definitions(id) on delete cascade,tool_code text not null,label text not null,risk text not null,allowed boolean not null default false,approval_class text,reason text not null,created_at timestamptz not null default now(),unique(command_id,tool_code));
create table if not exists public.revenue_os_command_triggers(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,code text unique not null,command_code text not null references public.revenue_os_command_definitions(command_code),trigger_type text not null check(trigger_type in('manual','scheduled','event','condition','chained','dependency','simulation')),source text not null,event_type text,condition_expression text,active boolean not null default true,replay_window_minutes integer not null default 0,priority integer not null default 50,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_schedules(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,code text unique not null,command_code text not null references public.revenue_os_command_definitions(command_code),label text not null,enabled boolean not null default true,timezone text not null default 'Africa/Casablanca',cadence text not null,business_hours_only boolean not null default true,next_run_at timestamptz,last_run_at timestamptz,missed_run_policy text not null check(missed_run_policy in('skip','run-once','reschedule')),owner_role text not null,execution_mode text not null check(execution_mode in('shadow','simulation')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_graphs(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,code text not null,version text not null,name text not null,description text not null,status text not null check(status in('draft','approved','retired')),graph_payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(code,version));
create table if not exists public.revenue_os_command_graph_nodes(id uuid primary key default gen_random_uuid(),graph_id uuid not null references public.revenue_os_command_graphs(id) on delete cascade,node_code text not null,command_code text not null,command_version text not null,sort_order integer not null,required boolean not null default true,approval_interrupt boolean not null default false,on_success jsonb not null default '[]',on_failure jsonb not null default '[]',created_at timestamptz not null default now(),unique(graph_id,node_code));
create table if not exists public.revenue_os_command_run_plans(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,situation_id text not null,idempotency_key text not null unique,execution_mode text not null,context_snapshot_id uuid,plan_payload jsonb not null,deterministic_hash text not null,approval_classes jsonb not null default '[]',prohibited_actions jsonb not null default '[]',created_by uuid,created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_runs(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,plan_id uuid references public.revenue_os_command_run_plans(id) on delete restrict,command_code text not null,command_version text not null,status text not null,attempt integer not null default 1,started_at timestamptz,completed_at timestamptz,output jsonb,validation_errors jsonb not null default '[]',failure_kind text,failure_message text,fallback_run_id uuid,approval_id uuid,trace_reference text not null,rollback_reference text,created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_run_steps(id uuid primary key default gen_random_uuid(),run_id uuid not null references public.revenue_os_command_runs(id) on delete cascade,sort_order integer not null,step_code text not null,status text not null,input_payload jsonb,output_payload jsonb,intended_tools jsonb not null default '[]',actual_tools jsonb not null default '[]',started_at timestamptz,completed_at timestamptz,error jsonb,created_at timestamptz not null default now(),unique(run_id,step_code));
create table if not exists public.revenue_os_command_idempotency(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,idempotency_key text unique not null,resource_type text not null,resource_id uuid,status text not null,expires_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_approval_classes(code text primary key,label text not null,risk_rank integer not null,description text not null,external_action_allowed boolean not null default false,created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_permission_evaluations(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,run_plan_id uuid,command_code text not null,actor_id uuid,actor_role text,required_permission text,decision text not null,reasons jsonb not null default '[]',evaluated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_output_validations(id uuid primary key default gen_random_uuid(),run_id uuid,command_code text not null,command_version text not null,valid boolean not null,errors jsonb not null default '[]',validator_chain jsonb not null default '[]',validated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_rollbacks(id uuid primary key default gen_random_uuid(),organization_id uuid,tenant_id uuid,command_code text not null,from_version text not null,to_version text not null,reason text not null,authorized_by uuid,affected_schedules jsonb not null default '[]',affected_graphs jsonb not null default '[]',created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_retirements(id uuid primary key default gen_random_uuid(),command_code text not null,version text not null,replacement_command_code text,reason text not null,retired_by uuid,retired_at timestamptz not null default now());
create table if not exists public.revenue_os_command_test_cases(id uuid primary key default gen_random_uuid(),case_code text unique not null,command_code text,category text not null,input_payload jsonb not null,expected_payload jsonb not null,prohibited_actions jsonb not null default '[]',active boolean not null default true,created_at timestamptz not null default now());
create table if not exists public.revenue_os_command_test_runs(id uuid primary key default gen_random_uuid(),case_id uuid not null references public.revenue_os_command_test_cases(id),command_version text,status text not null,actual_payload jsonb,failures jsonb not null default '[]',duration_ms integer,executed_at timestamptz not null default now());
create table if not exists public.revenue_os_command_kernel_validation_issues(id uuid primary key default gen_random_uuid(),issue_code text not null,severity text not null,category text not null,title text not null,detail text not null,status text not null default 'open',resource_type text not null,resource_id text,remediation text not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.revenue_os_command_kernel_snapshots(id uuid primary key default gen_random_uuid(),snapshot_code text unique not null,registry_hash text not null,command_count integer not null,family_count integer not null,readiness jsonb not null,external_actions_enabled boolean not null default false,execution_posture text not null default 'shadow',created_at timestamptz not null default now());
create or replace function public.revenue_os_command_prevent_published_mutation() returns trigger language plpgsql as $$begin if old.status in('approved','superseded','retired','audited') then raise exception 'Published command versions are immutable'; end if; return new; end$$;
drop trigger if exists revenue_os_command_versions_immutable on public.revenue_os_command_versions;create trigger revenue_os_command_versions_immutable before update or delete on public.revenue_os_command_versions for each row execute function public.revenue_os_command_prevent_published_mutation();
create index if not exists revenue_os_command_definitions_family_idx on public.revenue_os_command_definitions(family_code,status);create index if not exists revenue_os_command_runs_plan_idx on public.revenue_os_command_runs(plan_id,status);create index if not exists revenue_os_command_schedules_due_idx on public.revenue_os_command_schedules(enabled,next_run_at);create index if not exists revenue_os_command_triggers_event_idx on public.revenue_os_command_triggers(active,event_type);
insert into public.revenue_os_command_approval_classes(code,label,risk_rank,description,external_action_allowed) values
('none','Aucune approbation',0,'Lecture, analyse ou simulation sans effet externe.',false),('recommendation','Recommandation',1,'Recommandation interne sans engagement.',false),('internal-generation','Génération interne',2,'Création d’un artefact interne.',false),('supervisor','Superviseur',3,'Interruption requise au niveau superviseur.',false),('department','Département',4,'Validation départementale.',false),('director','Direction',5,'Validation direction.',false),('executive','Exécutif',6,'Validation exécutive.',false),('prohibited','Prohibée',99,'Action interdite.',false)
on conflict(code) do update set label=excluded.label,risk_rank=excluded.risk_rank,description=excluded.description,external_action_allowed=false;

insert into public.revenue_os_command_families(code,name,description,target_count,sort_order,owner_role) values
('market-sensing','Veille marché & opportunités','Détection de signaux et opportunités.',250,10,'Chief Revenue Intelligence'),('segmentation-account-discovery','Segmentation & découverte comptes','Priorisation ICP, comptes et décideurs.',300,20,'Market Intelligence Strategist'),('offer-pricing','Offres, packaging & prix','Architecture offre, valeur et marge.',250,30,'Offer & Monetization Architect'),('campaign-go-to-market','Campagnes & go-to-market','Stratégies d’attaque et vagues.',300,40,'Revenue Strategy Lead'),('outreach-channel','Outreach & orchestration canaux','Séquences et canaux contrôlés.',400,50,'Sales Conversion Strategist'),('qualification-progression','Qualification & progression','Progression commerciale fondée sur preuves.',250,60,'Commercial Excellence Lead'),('meetings-diagnostics','Réunions, diagnostics & démonstrations','Interactions de conversion.',200,70,'Meeting Conversion Strategist'),('proposal-negotiation-closing','Propositions, négociation & closing','Protection valeur et closing.',250,80,'Closing Architect'),('pipeline-rescue','Accélération pipeline & rescue','Déblocage et récupération revenu.',250,90,'Revenue Rescue Lead'),('renewal-expansion-referral','Renouvellement & expansion','Expansion et fidélisation.',200,100,'Customer Revenue Lead'),('executive-forecasting','Scénarios exécutifs & prévisions','Simulation et prévision.',150,110,'Executive Revenue Office'),('audit-optimization','Audit & optimisation continue','Validation et amélioration continue.',200,120,'Independent Revenue Auditor')
on conflict(code) do update set name=excluded.name,description=excluded.description,target_count=excluded.target_count,sort_order=excluded.sort_order,owner_role=excluded.owner_role,active=true,updated_at=timezone('utc',now());

