on conflict(command_code) do update set name=excluded.name,family_code=excluded.family_code,purpose=excluded.purpose,owner_role=excluded.owner_role,status=excluded.status,active_version=excluded.active_version,business_units=excluded.business_units,segments=excluded.segments,territories=excluded.territories,commercial_stages=excluded.commercial_stages,trigger_types=excluded.trigger_types,eligibility_rules=excluded.eligibility_rules,required_context=excluded.required_context,optional_context=excluded.optional_context,tool_permissions=excluded.tool_permissions,input_schema=excluded.input_schema,output_schema=excluded.output_schema,validator_chain=excluded.validator_chain,approval_class=excluded.approval_class,cooldown_policy=excluded.cooldown_policy,retry_policy=excluded.retry_policy,failure_policy=excluded.failure_policy,fallback_command_codes=excluded.fallback_command_codes,performance_metrics=excluded.performance_metrics,prohibited_cases=excluded.prohibited_cases,expected_outcomes=excluded.expected_outcomes,tags=excluded.tags,updated_at=timezone('utc',now());

insert into public.revenue_os_command_versions(command_id,command_code,version,status,snapshot,schema_hash,effective_at,approved_at,change_summary)
select id,command_code,active_version,status,to_jsonb(d),encode(digest(command_code||':'||active_version||':'||to_jsonb(d)::text,'sha256'),'hex'),timezone('utc',now()),case when status='approved' then timezone('utc',now()) else null end,'Version fondatrice MZ05.' from public.revenue_os_command_definitions d where command_code in ('REV-MANUAL-ACCOUNT-READINESS','REV-SCHEDULED-STALE-OPPORTUNITY-SCAN','REV-EVENT-POSITIVE-REPLY-TRIAGE','REV-CONDITION-MISSING-DECISION-MAKER','REV-CHAIN-ACCOUNT-QUALIFICATION','REV-CHAIN-DECISION-MAKER-RESEARCH','REV-FALLBACK-REQUEST-CAPACITY-CONTEXT','REV-OFFER-RECOMMENDATION-SHADOW','REV-APPROVAL-PRICING-EXCEPTION','REV-REJECT-EXTERNAL-MESSAGE','REV-SIMULATE-STALL-RESCUE','REV-AUDIT-ROUTING-DECISION') on conflict(command_code,version) do nothing;

insert into public.revenue_os_command_eligibility_rules(command_id,rule_code,field_path,operator,expected_value,weight,hard_block,reason,sort_order)
select d.id,coalesce(r->>'id','rule-'||ordinality),r->>'field',r->>'operator',r->'value',coalesce((r->>'weight')::integer,0),coalesce((r->>'hardBlock')::boolean,false),coalesce(r->>'reason','Règle gouvernée.'),ordinality from public.revenue_os_command_definitions d cross join lateral jsonb_array_elements(d.eligibility_rules) with ordinality as x(r,ordinality) on conflict(command_id,rule_code) do update set field_path=excluded.field_path,operator=excluded.operator,expected_value=excluded.expected_value,weight=excluded.weight,hard_block=excluded.hard_block,reason=excluded.reason,sort_order=excluded.sort_order;

insert into public.revenue_os_command_context_contracts(command_id,context_key,label,required,freshness_minutes,allowed_states,source_domains,confidentiality)
select d.id,c->>'key',c->>'label',coalesce((c->>'required')::boolean,true),nullif(c->>'freshnessMinutes','')::integer,coalesce(c->'allowedStates','["available"]'::jsonb),coalesce(c->'sourceDomains','[]'::jsonb),coalesce(c->>'confidentiality','internal') from public.revenue_os_command_definitions d cross join lateral jsonb_array_elements(d.required_context) c on conflict(command_id,context_key) do update set label=excluded.label,required=excluded.required,freshness_minutes=excluded.freshness_minutes,allowed_states=excluded.allowed_states,source_domains=excluded.source_domains,confidentiality=excluded.confidentiality;

insert into public.revenue_os_command_tool_permissions(command_id,tool_code,label,risk,allowed,approval_class,reason)
select d.id,t->>'toolCode',t->>'label',t->>'risk',coalesce((t->>'allowed')::boolean,false),t->>'approvalClass',t->>'reason' from public.revenue_os_command_definitions d cross join lateral jsonb_array_elements(d.tool_permissions) t on conflict(command_id,tool_code) do update set label=excluded.label,risk=excluded.risk,allowed=excluded.allowed,approval_class=excluded.approval_class,reason=excluded.reason;

