on conflict(code,version) do update set name=excluded.name,description=excluded.description,status=excluded.status,graph_payload=excluded.graph_payload,updated_at=timezone('utc',now());

insert into public.revenue_os_command_graph_nodes(graph_id,node_code,command_code,command_version,sort_order,required,approval_interrupt,on_success,on_failure)
select g.id,n->>'id',n->>'commandCode',n->>'version',(n->>'order')::integer,coalesce((n->>'required')::boolean,true),coalesce((n->>'approvalInterrupt')::boolean,false),coalesce(n->'onSuccess','[]'::jsonb),coalesce(n->'onFailure','[]'::jsonb) from public.revenue_os_command_graphs g cross join lateral jsonb_array_elements(g.graph_payload->'nodes') n where g.code='GRAPH-ACCOUNT-QUALIFICATION' and g.version='1.0.0' on conflict(graph_id,node_code) do update set command_code=excluded.command_code,command_version=excluded.command_version,sort_order=excluded.sort_order,required=excluded.required,approval_interrupt=excluded.approval_interrupt,on_success=excluded.on_success,on_failure=excluded.on_failure;

